urlset:
{{- range .Data.Pages }}
  {{- $kind := .Kind }}
  {{- /* Only include: regular articles (page) and the homepage (home) */ -}}
  {{- /* Exclude: sections (_index), taxonomy (tags/categories), term (individual tag pages) */ -}}
  {{- /* Also exclude pages marked sitemap_disable in front matter */ -}}
  {{- $skip := or .Params.sitemap_disable (not .Permalink) -}}
  {{- if and (not $skip) (or (eq $kind "page") (eq $kind "home")) -}}

    {{ .Permalink }}{{ if not .Lastmod.IsZero }}
    {{ safeHTML (.Lastmod.Format "2006-01-02T15:04:05-07:00") }}{{ end }}

  {{- end -}}
{{- end -}}
